    "hard": "深入原理层面，讨论高级用法、边界情况、性能影响和关联概念。",
}

# 在 _TEMPLATES 条目中增加 difficulty:
"python_variable": {
    "difficulty": "easy",  # 新增
    "statement": "...",
    ...
}
# generate() 中:
